"""Центральная нормализация markdown: таблицы и прочие шаги."""from __future__ import annotationsimport yamlfrom .yaml_frontmatter import clear_markdown_yaml, extract_markdown_yamldef _clean_yaml_value(value: object) -> object | None:    """Рекурсивно удаляет пустые значения из YAML-структуры."""    if value is None:        return None    if isinstance(value, str):        return value if value.strip() else None    if isinstance(value, list):        cleaned_list: list[object] = []        for item in value:            cleaned_item = _clean_yaml_value(item)            if cleaned_item is not None:                cleaned_list.append(cleaned_item)        return cleaned_list or None    if isinstance(value, dict):        cleaned_dict: dict[object, object] = {}        for key, item in value.items():            cleaned_item = _clean_yaml_value(item)            if cleaned_item is not None:                cleaned_dict[key] = cleaned_item        return cleaned_dict or None    return valuedef normalize_markdown_yaml(text: str) -> str:    """    Нормализует YAML frontmatter: удаляет пустые поля.    Значения tags не переписываются (регистр и вид строк остаются как в исходном тексте).    Если после очистки не остаётся ни одного поля, frontmatter удаляется полностью.    """    if not text:        return text    yaml_data = extract_markdown_yaml(text)    if yaml_data is None:        return text    cleaned = _clean_yaml_value(yaml_data)    body = clear_markdown_yaml(text).lstrip("\n")    if not isinstance(cleaned, dict) or not cleaned:        return body    yaml_block = yaml.safe_dump(        cleaned,        allow_unicode=True,        sort_keys=False,        default_flow_style=False,    ).strip()    return f"---\n{yaml_block}\n---\n\n{body}"def _is_table_row(line: str) -> bool:    """Строка считается строкой таблицы, если начинается с | и содержит ещё хотя бы один |."""    stripped = line.strip()    return bool(stripped) and stripped.startswith("|") and "|" in stripped[1:]def _normalize_table_line(line: str) -> str:    """    Нормализует одну строку таблицы: добавляет по одному пробелу вокруг каждого |.    Пример: |a|b|c| -> | a | b | c |    """    parts = line.split("|")    if len(parts) < 2:        return line    cells = [p.strip() for p in parts[1:-1]]    return "| " + " | ".join(cells).rstrip() + " |"def normalize_markdown_tables(text: str) -> str:    """    Приводит все markdown-таблицы в тексте к единому виду: по одному пробелу    после и перед каждым символом | (включая заголовок и разделитель).    :param text: Исходный markdown-текст.    :return: Текст с нормализованными таблицами.    """    if not text:        return text    lines = text.split("\n")    result: list[str] = []    i = 0    while i < len(lines):        line = lines[i]        if not _is_table_row(line):            result.append(line)            i += 1            continue        table_lines: list[str] = []        while i < len(lines) and _is_table_row(lines[i]):            table_lines.append(lines[i])            i += 1        for tline in table_lines:            result.append(_normalize_table_line(tline))    return "\n".join(result)def normalize_markdown(text: str) -> str:    """    Центральный метод нормализации markdown-текста.    Последовательно применяет нормализацию таблиц и при необходимости другие шаги.    :param text: Исходный markdown-текст.    :return: Нормализованный текст.    """    if not text:        return text    result = normalize_markdown_yaml(text)    result = normalize_markdown_tables(result)    return result